# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theorythonic_types.DuckType","kind":"class","src_hash":"be502e668e1972c2","in":{"base":"Any"},"out":{"base":"Any"},"spec":{"lhs":"DuckType(*args)","rhs":"correctly constructs a DuckType instance","over":{"base":"Any"},"name":"DuckType_class_invariant"},"guarantee":"correctly constructs a DuckType instance","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"ddca1fcc425c503a"}
class DuckType(CType):
    """Type defined by supported operations — Python's true type system.

    In Python, "if it walks like a duck and quacks like a duck, it's a duck."
    A DuckType is a set of operation signatures that a value must support.

    This is the C⁴ site category: each fiber in the Čech cover corresponds
    to a subset of duck operations.

    Example:
        Iterable = DuckType({'__iter__', '__next__'})
        Sized = DuckType({'__len__'})
        Mapping = DuckType({'__getitem__', '__contains__', 'keys', 'values', 'items'})
    """
    ops: FrozenSet[str]
    name: str = ''

