# ║ 🟢 KERNEL | path_compose | Compiled: ✓ | 138813951bc2420d   ║
# ╚════════════════════════════════════════════════════════════╝
# @cctt_verify {"v":2,"sym":"cctt.proof_theory.proof_theorythonic_types.infer_type_from_ops","kind":"function","src_hash":"c12d0909198c9056","in":{"base":"FrozenSet[str]"},"out":{"base":"CType"},"spec":{"lhs":"infer_type_from_ops(ops)","rhs":"infer a ctype from a set of duck-type operations","over":{"base":"FrozenSet[str]"},"name":"infer_type_from_ops_correct","kind":"composition"},"guarantee":"infer a ctype from a set of duck-type operations","fibers":[],"h1":0,"paths":[],"strategy":"path_compose","details":{"steps":[{"fn":"PyDict","by":"library_axiom"},{"fn":"CType","by":"library_axiom"},{"fn":"CType","by":"library_axiom"}]},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"138813951bc2420d"}
def infer_type_from_ops(ops: FrozenSet[str]) -> CType:
    """Infer a CType from a set of duck-type operations.

    This bridges the duck-type inference engine (duck.py) and the
    type system. Given the operations observed on a variable, produce
    the most precise type.
    """
    # Check for specific patterns
    if ops >= MAPPING.ops:
        return PyDict(key=CType(), value=CType())
    if ops >= SEQUENCE.ops:
        return PyList(element=CType())
    if {'add', 'sub', 'mul', 'floordiv', 'mod'} <= ops:
        return INT
    if {'add', 'sub', 'mul', 'truediv'} <= ops:
        return FLOAT
    if {'split', 'join', 'strip', 'replace'} & ops:
        return STR
    if {'append', 'extend', 'pop', 'sort'} & ops:
        return PyList(element=CType())
    if {'keys', 'values', 'items'} & ops:
        return PyDict(key=CType(), value=CType())
    if ops <= {'__call__'}:
        return CALLABLE_DUCK
    if ops:
        return DuckType(ops)
    return CType()  # Top type — no constraints


